import itertools

class Solution:
    def maximumAND(self, nums, k, m):
        BITS = 31
        def min_cover(x, mask):
            y = 0
            tight = True
            for b in range(BITS - 1, -1, -1):
                mb = (mask >> b) & 1
                xb = (x >> b) & 1
                if tight:
                    if mb == 1:
                        yb = 1
                        if yb > xb:
                            tight = False
                    else:
                        yb = xb
                else:
                    yb = mb
                y = (y << 1) | yb
            return y
        n = len(nums)
        best = 0
        for combo in itertools.combinations(range(n), m):
            chosen = [nums[i] for i in combo]
            cur = 0
            for b in range(BITS - 1, -1, -1):
                cand = cur | (1 << b)
                total = 0
                ok = True
                for x in chosen:
                    total += min_cover(x, cand) - x
                    if total > k:
                        ok = False
                        break
                if ok:
                    cur = cand
            if cur > best:
                best = cur
        return best

