class Solution:
    def maximumAND(self, nums, k: int, m: int) -> int:
        BITS = 31

        def min_cover(x, mask):
            y = 0
            tight = True
            for b in range(BITS - 1, -1, -1):
                mb = (mask >> b) & 1
                xb = (x >> b) & 1
                if tight:
                    if mb == 1:
                        yb = 1
                        if yb > xb:
                            tight = False
                    else:
                        yb = xb
                else:
                    yb = mb
                y = (y << 1) | yb
            return y

        def feasible(mask):
            costs = [min_cover(x, mask) - x for x in nums]
            costs.sort()
            return sum(costs[:m]) <= k

        ans = 0
        for b in range(BITS - 1, -1, -1):
            cand = ans | (1 << b)
            if feasible(cand):
                ans = cand
        return ans

