var maximumAND = function(nums, k, m) {
    const BITS = 31;
    function minCover(x, mask) {
        let y = 0;
        let tight = true;
        for (let b = BITS - 1; b >= 0; b--) {
            const mb = (mask >>> b) & 1;
            const xb = (x >>> b) & 1;
            let yb;
            if (tight) {
                if (mb === 1) {
                    yb = 1;
                    if (yb > xb) tight = false;
                } else {
                    yb = xb;
                }
            } else {
                yb = mb;
            }
            y = y * 2 + yb;
        }
        return y;
    }
    function feasible(mask) {
        const costs = nums.map((x) => minCover(x, mask) - x);
        costs.sort((a, b) => a - b);
        let total = 0;
        for (let i = 0; i < m; i++) total += costs[i];
        return total <= k;
    }
    let ans = 0;
    for (let b = BITS - 1; b >= 0; b--) {
        const cand = ans | (1 << b);
        if (feasible(cand)) ans = cand;
    }
    return ans;
};
